from collections import defaultdict
from typing import List

class Solution:
    def countPairs(self, coordinates: List[List[int]], k: int) -> int:
        freq = defaultdict(int)
        count = 0

        for x, y in coordinates:
            for x2 in range(x ^ k + 1):
                y2 = (x ^ x2) + (y ^ k) - y
                if y2 >= 0:
                    count += freq[(x2, y2)]
            freq[(x, y)] += 1

        return count
